## 指针和数组

### 数组名

除了以下两种情况外，一般情况下，数组名都代表数组首元素的地址。

数组名代表整个数组的情况：

1. `sizeof`中的数组名(**只出现数组名**)代表整个数组。`sizeof(arr)`这里的数组名代表的是整个数组，但是`sizeof(arr+0)`代表首元素**地址**的大小。

2. `&arr`代表整个数组。(实际上`&arr`表示的是数组的地址，而不是数组首元素的地址，数组的地址+1，会跳过整个数组的大小)

```c
int arr[5] = {1,2,3,4,5};
printf("sizeof(arr) -> %d\n", sizeof(arr));
printf("sizeof(arr+0) -> %d\n", sizeof(arr+0));
printf("sizeof(&arr) -> %d\n", sizeof(&arr));
printf("arr -> %p\n", arr);
printf("&arr -> %p\n", &arr);
printf("arr+1 -> %p\n", arr+1);
printf("&arr+1 -> %p\n", &arr+1);
```

输出：

```c
sizeof(arr) -> 20
sizeof(arr+0) -> 8	// 64bit环境下指针的大小为8字节，32bit环境下指针的大小为4字节，这里arr+0代表的是首元素地址
sizeof(&arr) -> 8	// 数组的地址大小(也是一个地址)，占8个字节。
arr -> 0x7ffeef8929a0
&arr -> 0x7ffeef8929a0
arr+1 -> 0x7ffeef8929a4		// 跳过了一个元素
&arr+1 -> 0x7ffeef8929b4	// 这里跳过了整个数组的大小(20)
```

对指针+1，实际上加的是这个指针类型的大小，比如整型指针+1，地址+4。

### 区分指针数组和数组指针

指针**数组**：是一个数组，数组的元素的指针。

数组**指针**：是一个指针，指向数组的指针。

从字面意思上来看就是谁在后就是什么东西。

```c
int *p1[10];
int (*p2)[10];
```

`int *p1[10]`这里的p1先和`[]`结合，所以他是数组，是指针数组。

`int (*p2)[10]`p2先和`*`结合，是指针，是数组指针。

### 数组指针的使用

数组指针  指向数组，那么数组指针中存的就是数组的地址咯。

```c
int main(int argc, const char * argv[])
{
    int arr[10] = {1,2,3,4,5,6,7,8,9,0};
    int (*p)[10] = &arr;
    return 0;
}
```

但一般不这么使用。一个数组指针的使用：

```c
void init_arr(int (*arr)[5], int row, int col)
{
    for(int i=0; i<row; i++)
    {
        for(int j=0; j<col; j++)
        {
            arr[i][j] = i+j;
        }
    }
}

void disp_arr(int (*arr)[5], int row, int col)
{
    for(int i=0; i<row; i++)
    {
        for(int j=0; j<col; j++)
        {
            printf("%d ", arr[i][j]);
        }
        printf("\n");
    }
}

int main()
{
    int arr[3][5] = {0};

    init_arr(arr, 3, 5);
    disp_arr(arr, 3, 5);

    return 0;
}
```

### 数组传参，指针传参

- 一维数组传参

  ```c
  void test11(int arr[]){;}  // ok
  void test12(int arr[10]){;}    // ok
  void test13(int *arr){;}   // ok

  void test21(int *arr[20]){;}   // ok
  void test22(int **arr){;}  // ok

  int main()
  {
      int arr1[10] = {0};
      int *arr2[20] = {0};  //// 数组指针
      test11(arr1);
      test12(arr1);
      test13(arr1);

      test21(arr2);
      test22(arr2);

      return 0;
  }
  ```

- 二维数组传参

  ```c
  void test(int arr[3][5]){;} // ok
  void test(int arr[][]){;}   // error!
  void test(int arr[][5]){;}  // ok
  void test(int *arr){;}  // error!

  void test(int* arr[5]){;} // error!
  void test(int (*arr)[5]){;} // OK!
  void test(int **arr){;} // error!

  int main()
  {
      int arr[3][5] = {0};
      test(arr);
      return 0;
  }
  ```



- 一级指针传参

  ```c
  void print(int *p, int size)
  {
      for(int i=0; i<size; i++)
      {
          printf("%d\n", *(p+i));
      }
  }

  int main()
  {
      int arr[10] = {1,2,3,4,5,6,7,8,9};
      int *p = arr;
      int size = sizeof(arr)/sizeof(arr[0]);
      print(p, size);

      return 0;
  }
  ```

- 二级指针传参

  ```c
  void test(int **p)
  {
      printf("%d\n", **p);
  }

  int main()
  {
      int n = 10;
      int *p = &n;
      int **pp = &p;
      test(&p);
      test(pp);

      return 0;
  }
  ```

## 函数指针

### 函数指针

函数名代表的是函数地址

```c
int test()
{
    printf("ahoj\n");
    return 0;
}

int main()
{
    printf("test    %p\n", test);
    printf("&test   %p\n", &test);
    test();

    return 0;
}
```

输出：

```c
test    0x100000ef0
&test   0x100000ef0
ahoj
```

函数也是有地址滴，要保存函数地址，就要用到函数指针。

```c
void (*pf1)();	// 函数指针，先和*结合，再与()结合。pf1是一个指针，指向一个无参数的函数，返回值为void
void *pf2();	// 返回值为void *的函数
```

到这里才理解了《C陷阱和缺陷》里的那段代码：`(*(void (*)())0)();`

这里的$0$被强制转换为`void(*)()`，函数指针=>解引用，0代表一个函数的地址（地址为0处的函数）

再来看个代码：`void (*signal(int, void(*)(int)))(int);`

这是一段函数声明，函数的返回值为：signal先与*结合=>是个函数指针，指向一个参数为`(int, 函数指针类型)`的一个函数。参数为：int。

对于上面的两行代码，太复杂，需要简化一下：

```c
typedef void(*pfun_t)(int);	// pfun_t是一个函数指针，指向一个参数为int的函数
pfun_t signal(int, pfun_t);	// signal的返回值是个函数指针，参数是int和一个函数指针
```

### 函数指针数组

数组用来存放相同类型数据的，那么把函数的地址存到一个数组中，这个数组就叫做**函数指针数组**。

`int (*parr[10])();`

`parr`先和`[]`结合，说明`parr`是个数组，数组的内容是什么类型呢？是`int (*)()`类型的函数指针。

- 函数指针数组的用途：**转移表**（例子：计算器）

  普通版：

  ```c
  #include <stdio.h>

  int add(int a, int b)
  {
      return a+b;
  }
  int sub(int a, int b)
  {
      return a-b;
  }
  int mul(int a, int b)
  {
      return a*b;
  }
  int diiv(int a, int b)
  {
      return a/b;
  }
  int main()
  {
      int x, y;
      int input = 1;
      int ret = 0;
      while(input)
      {
          printf("=========\n");
          printf("( 1. +  )\n");
          printf("( 2. -  )\n");
          printf("( 3. *  )\n");
          printf("( 4. \\  )\n");
          printf("=========\n");
          printf("choice>");
          scanf("%d", &input);
          switch(input)
          {
              case 1:
                  printf("<(a b)>");
                  scanf("%d%d", &x, &y);
                  ret = add(x, y);
                  break;
              case 2:
                  printf("<(a b)>");
                  scanf("%d%d", &x, &y);
                  ret = sub(x, y);
              case 3:
                  printf("<(a b)>");
                  scanf("%d%d", &x, &y);
                  ret = mul(x, y);
              case 4:
                  printf("<(a b)>");
                  scanf("%d%d", &x, &y);
                  ret = diiv(x, y);
              default:
                  printf("error!\n");
                  break;
          }
          printf("ret = %d\n", ret);
      }

      return 0;
  }
  ```

  函数指针数组实现：

  ```c
  int main()
  {
      int x, y;
      int input = 1;
      int ret = 0;
      int (*p[5])(int x, int y) = {0, add, sub, mul, diiv};   // 转移表
      while(input)
      {
          printf("=========\n");
          printf("( 1. +  )\n");
          printf("( 2. -  )\n");
          printf("( 3. *  )\n");
          printf("( 4. \\  )\n");
          printf("=========\n");
          printf("choice>");
          scanf("%d", &input);
          if((input<=4 && input>=1))
          {
              printf("a b >");
              scanf("%d%d", &x, &y);
              ret = (*p[input])(x,y);
          }
          else
          {
              printf("error!");
          }
          printf("ret = %d\n", ret);
      }

      return 0;
  }
  ```

### 指向函数指针数组的指针

上面这个东西，首先是个指针，指向一个数组，数组的元素是函数指针。

```c
void test(const char *str)
{
    printf("%s\n", str);
}

int main()
{
    // 函数指针pf
    void (*pf)(const char *) = test;

    // 函数指针的数组pfarr
    void (*pfarr[5])(const char *str);
    pfarr[0] = test;

    // 指向函数指针数组pfarr的指针ppfarr
    void (*(*ppfarr)[10])(const char *) = &pfarr;

    return 0;
}
```

### 回调函数

> 回调函数就是一个通过函数指针调用的函数。如果把函数的地址作为参数传递给另一个函数，当这个指针被用来调用其所指向的函数时，称为这是一个回调函数。
>
> 回调函数不是由该函数的实现方法直接调用，而是在特定的事件或条件发生时由另外的一方调用的，用于对事件或条件进行相应。
>
> [百度百科](https://baike.baidu.com/item/%E5%9B%9E%E8%B0%83%E5%87%BD%E6%95%B0/7545973?fr=aladdin)

简单认识qsort函数：

```c
#include <stdlib.h>
void
qsort(void *base, size_t nel, size_t width, int (*compar)(const void *, const void *));
```

返回值`void`，第一个参数是要排序的数组，第二个参数要排序数组元素的个数，第三个参数时每个元素的大小（所占字节数，比如int类型占4字节），第四个参数是一个比较大小用的回调函数（这个函数返回一个整数，参数为两个指针）。

qsort函数的使用：

```c
#include <stdio.h>
#include <math.h>
#include <stdlib.h>

int int_cmp(const void * p1, const void *p2)
{
//    return (*(int *)p1 < *(int *)p2); //这样只对正整数有效
    int x = *(int *)p1;
    int y = *(int *)p2;
    if(x < y)
        return -1;
    else if(x == y)
        return 0;
    else
        return 1;
}

int main(int argc, const char * argv[])
{
    int arr[] = {11,33,22,-11,-22,-300,32,0};

    qsort(arr, sizeof(arr)/sizeof(arr[0]), sizeof(int), int_cmp);

    for(int i=0; i<sizeof(arr)/sizeof(arr[0]); i++)
    {
        printf("%d ", arr[i]);
    }
    printf("\n");

    return 0;
}
```

使用冒泡排序模拟实现qsort这种类型的排序函数：

```C
#include <stdio.h>
#include <math.h>
#include <stdlib.h>

int int_cmp(const void * p1, const void *p2)
{
//    return (*(int *)p1 < *(int *)p2); //这样只对正整数有效
    int x = *(int *)p1;
    int y = *(int *)p2;
    if(x < y)
        return -1;
    else if(x == y)
        return 0;
    else
        return 1;
}

void swap(void *p1, void *p2, int size)
{
    for(int i=0; i<size; i++)
    {
        char tmp = *((char *)p1+i);
        *((char *)p1+i) = *((char *)p2+i);
        *((char *)p2+i) = tmp;
    }
}

void
myqsort(void *base,
        int len,
        int width,
        int (*cmp)(void *p1, void *p2))
{
    for(int i=0; i<len; i++)
    {
        for(int j=0; j<len-1-i; j++)
        {
            if( cmp((char *)base+j*width,(char *)base+(j+1)*width) > 0 )
            {
                swap((char *)base+j*width,
                     (char *)base+(j+1)*width,
                     sizeof(int));
            }
        }
    }
}

int main(int argc, const char * argv[])
{
    int arr[] = {11,33,22,-11,-22,-300,32,0};

    qsort(arr, sizeof(arr)/sizeof(arr[0]), sizeof(int), int_cmp);

    for(int i=0; i<sizeof(arr)/sizeof(arr[0]); i++)
    {
        printf("%d ", arr[i]);
    }
    printf("\n");

    return 0;
}
```



