![7](https://wx4.sinaimg.cn/mw690/006wR0dcly1fxnipjqiicj31460c475c.jpg)

8. 题

```c
int main()
{
    char *c[] = { "ENTER", "NEW", "POINT", "FIRST" };
    int **cp[] = { c+3, c+2, c+1, c };
    char ***cpp = cp;
    printf("%s\n", **++cpp);		// POINT
    printf("%s\n", *--*++cpp+3);	// ER
    printf("%s\n", *cpp[-2]+3);		// ST
    printf("%s\n", cpp[-1][-1]+1);	// EW

    return 0;
}
```

`++、—`的优先级高于`*`，`*`的优先级高于`+`。`++cpp`会影响`cpp`的值，但`cpp+1`不会影响。`[]`的优先级大于`*`。

![8.1](https://wx2.sinaimg.cn/mw690/006wR0dcly1fxnj61eghkj31fy0l0q5n.jpg)

`**++cpp`：先`++`，此时的`cpp`指向`cp[1]`，解引用为`c[2]`，再解引用即为`POINT`。

![8.2](https://wx2.sinaimg.cn/mw690/006wR0dcly1fxnjdh5q1zj31fq0k00ve.jpg)

`*--*++cpp+3`：经过上一步，`cpp`现在的指向如上图。

先`++`，此时`cpp`指向`cp[2]`，解引用即为`cp[2]`，再`--`，此时改变了`cp[2]`的指向，他指向`c[0]`，再解引用即为`c[0]`，给`c[0]+3`，输出的结果为`ER`。

![8.3](https://wx2.sinaimg.cn/mw690/006wR0dcly1fxnjlyh6yzj31jm0hy0vf.jpg)

`*cpp[-2]+3`：经过上一步，现在的指向如上图所示。

`cpp[-2]`指向了`cp[0]`，解引用指向`c[3]`，`c[3]+3`输出`ST`。

`cpp[-1][-1]+1`：经过上一步并没有改变指针的指向。

`cpp[-1][-1]`代表`c[1]`，再`+1`输出`EW`。

## 指针和数组

### 数组名

除了以下两种情况外，一般情况下，数组名都代表数组首元素的地址。

数组名代表整个数组的情况：

1. `sizeof`中的数组名(**只出现数组名**)代表整个数组。`sizeof(arr)`这里的数组名代表的是整个数组，但是`sizeof(arr+0)`代表首元素**地址**的大小。

2. `&arr`代表整个数组。(实际上`&arr`表示的是数组的地址，而不是数组首元素的地址，数组的地址+1，会跳过整个数组的大小)

```c
int arr[5] = {1,2,3,4,5};
printf("sizeof(arr) -> %d\n", sizeof(arr));
printf("sizeof(arr+0) -> %d\n", sizeof(arr+0));
printf("sizeof(&arr) -> %d\n", sizeof(&arr));
printf("arr -> %p\n", arr);
printf("&arr -> %p\n", &arr);
printf("arr+1 -> %p\n", arr+1);
printf("&arr+1 -> %p\n", &arr+1);
```

输出：

```c
sizeof(arr) -> 20
sizeof(arr+0) -> 8	// 64bit环境下指针的大小为8字节，32bit环境下指针的大小为4字节，这里arr+0代表的是首元素地址
sizeof(&arr) -> 8	// 数组的地址大小(也是一个地址)，占8个字节。
arr -> 0x7ffeef8929a0
&arr -> 0x7ffeef8929a0
arr+1 -> 0x7ffeef8929a4		// 跳过了一个元素
&arr+1 -> 0x7ffeef8929b4	// 这里跳过了整个数组的大小(20)
```

对指针+1，实际上加的是这个指针类型的大小，比如整型指针+1，地址+4。

### 区分指针数组和数组指针

指针**数组**：是一个数组，数组的元素的指针。

数组**指针**：是一个指针，指向数组的指针。

从字面意思上来看就是谁在后就是什么东西。

```c
int *p1[10];
int (*p2)[10];
```

`int *p1[10]`这里的p1先和`[]`结合，所以他是数组，是指针数组。

`int (*p2)[10]`p2先和`*`结合，是指针，是数组指针。

### 数组指针的使用

数组指针  指向数组，那么数组指针中存的就是数组的地址咯。

```c
int main(int argc, const char * argv[])
{
    int arr[10] = {1,2,3,4,5,6,7,8,9,0};
    int (*p)[10] = &arr;
    return 0;
}
```

但一般不这么使用。一个数组指针的使用：

```c
void init_arr(int (*arr)[5], int row, int col)
{
    for(int i=0; i<row; i++)
    {
        for(int j=0; j<col; j++)
        {
            arr[i][j] = i+j;
        }
    }
}

void disp_arr(int (*arr)[5], int row, int col)
{
    for(int i=0; i<row; i++)
    {
        for(int j=0; j<col; j++)
        {
            printf("%d ", arr[i][j]);
        }
        printf("\n");
    }
}

int main()
{
    int arr[3][5] = {0};

    init_arr(arr, 3, 5);
    disp_arr(arr, 3, 5);

    return 0;
}
```

### 数组传参，指针传参

- 一维数组传参

  ```c
  void test11(int arr[]){;}  // ok
  void test12(int arr[10]){;}    // ok
  void test13(int *arr){;}   // ok

  void test21(int *arr[20]){;}   // ok
  void test22(int **arr){;}  // ok

  int main()
  {
      int arr1[10] = {0};
      int *arr2[20] = {0};  //// 数组指针
      test11(arr1);
      test12(arr1);
      test13(arr1);

      test21(arr2);
      test22(arr2);

      return 0;
  }
  ```

- 二维数组传参

  ```c
  void test(int arr[3][5]){;} // ok
  void test(int arr[][]){;}   // error!
  void test(int arr[][5]){;}  // ok
  void test(int *arr){;}  // error!

  void test(int* arr[5]){;} // error!
  void test(int (*arr)[5]){;} // OK!
  void test(int **arr){;} // error!

  int main()
  {
      int arr[3][5] = {0};
      test(arr);
      return 0;
  }
  ```



- 一级指针传参

  ```c
  void print(int *p, int size)
  {
      for(int i=0; i<size; i++)
      {
          printf("%d\n", *(p+i));
      }
  }

  int main()
  {
      int arr[10] = {1,2,3,4,5,6,7,8,9};
